import "./Home.css";
import profile from "../assets/profile.webp";
import { Link } from "react-router-dom";
import { Helmet } from "react-helmet-async"; 

function Home() {
  return (
    <main className="home">

      <Helmet>
        <title>
          Arouna Kouotou - Intégrateur Web
        </title>

        <meta
          name="description"
          content="Portfolio de Kouotou Arouna, intégrateur web diplômé spécialisé en React, HTML, CSS, Redux toolkit et JavaScript."
        />
      </Helmet>

      <section className="hero">
        <img src={profile} alt="Kouotou Arouna développeur web" className="profile-img" />

        <div className="hero-text">
          <h1>Kouotou Arouna</h1>
          <h2>Intégrateur Web diplômé</h2>

          <p>
            Je suis intégrateur web passionné, spécialisé dans la création
            d’interfaces modernes, performantes et accessibles. Après ma formation,
            je conçois des sites web responsive en HTML, CSS, React, JavaScript et Redux toolkit.
          </p>

          <Link to="/projects" className="btn">
            Voir mes projets
          </Link>
        </div>
      </section>
    </main>
  );
}

export default Home;